for r in refs:
    p = doc.add_paragraph(); run = p.add_run(r); run.font.size = Pt(11)
    p.paragraph_format.space_after = Pt(4)
    p.paragraph_format.left_indent = Inches(0.4); p.paragraph_format.first_line_indent = Inches(-0.4)

doc.save(OUT)
w = 0
for p in doc.paragraphs: w += len(re.findall(r"\S+", p.text))
for t in doc.tables:
    for row in t.rows:
        for c in row.cells: w += len(re.findall(r"\S+", c.text))
emdash = sum(p.text.count("—") for p in doc.paragraphs)
print("SAVED", OUT)
print("word count:", w, "| refs:", len(refs), "| em-dashes:", emdash, "| figures:", len(doc.inline_shapes), "| tables:", len(doc.tables))
